bash_commands.command:
cat > /tmp/header_match_patch.txt << 'EOF'
--- a/src/backend/parser/gram.y
+++ b/src/backend/parser/gram.y
@@ -3495,6 +3495,10 @@ copy_opt_item:
 			{
 				$$ = makeDefElem("header", (Node *) makeBoolean(true), @1);
 			}
+		| HEADER_P MATCH
+			{
+				$$ = makeDefElem("header", (Node *) makeString("match"), @1);
+			}
 		| QUOTE opt_as Sconst
 			{
 				$$ = makeDefElem("quote", (Node *) makeString($3), @1);
EOF
patch -p1 < /tmp/header_match_patch.txt

cat >> /workspace/src/test/regress/sql/copy.sql << 'EOF'

-- Tests for HEADER MATCH option
-- Test matching headers
CREATE TEMP TABLE header_match_test (
	col1 int,
	col2 text,
	col3 float);

COPY header_match_test FROM stdin WITH (format csv, header match);
col1,col2,col3
1,a,1.5
2,b,2.5
\.

SELECT * FROM header_match_test;
TRUNCATE header_match_test;

-- Test case-insensitive header matching
COPY header_match_test FROM stdin WITH (format csv, header match);
COL1,COL2,COL3
3,c,3.5
4,d,4.5
\.

SELECT * FROM header_match_test;
TRUNCATE header_match_test;

-- Test mixed case header matching
COPY header_match_test FROM stdin WITH (format csv, header match);
Col1,cOl2,CoL3
5,e,5.5
6,f,6.5
\.

SELECT * FROM header_match_test;
TRUNCATE header_match_test;

-- Test mismatched headers (should fail)
COPY header_match_test FROM stdin WITH (format csv, header match);
col1,wrong_col2,col3
1,a,1.5
\.

-- Test wrong number of columns (should fail)
COPY header_match_test FROM stdin WITH (format csv, header match);
col1,col2
1,a
\.

-- Test HEADER MATCH with non-CSV format should fail
COPY header_match_test FROM stdin WITH (header match);
col1	col2	col3
1	a	1.5
\.

-- Test HEADER MATCH in COPY TO should fail
COPY header_match_test (col1, col2) TO stdout WITH (format csv, header match);

DROP TABLE header_match_test;
EOF

cat >> /workspace/src/test/regress/expected/copy.out << 'EOF'

-- Tests for HEADER MATCH option
-- Test matching headers
CREATE TEMP TABLE header_match_test (
	col1 int,
	col2 text,
	col3 float);
COPY header_match_test FROM stdin WITH (format csv, header match);
SELECT * FROM header_match_test;
 col1 | col2 | col3 
------+------+------
    1 | a    |  1.5
    2 | b    |  2.5
(2 rows)

TRUNCATE header_match_test;
-- Test case-insensitive header matching
COPY header_match_test FROM stdin WITH (format csv, header match);
SELECT * FROM header_match_test;
 col1 | col2 | col3 
------+------+------
    3 | c    |  3.5
    4 | d    |  4.5
(2 rows)

TRUNCATE header_match_test;
-- Test mixed case header matching
COPY header_match_test FROM stdin WITH (format csv, header match);
SELECT * FROM header_match_test;
 col1 | col2 | col3 
------+------+------
    5 | e    |  5.5
    6 | f    |  6.5
(2 rows)

TRUNCATE header_match_test;
-- Test mismatched headers (should fail)
COPY header_match_test FROM stdin WITH (format csv, header match);
ERROR:  column name mismatch in header line field 2: got "wrong_col2", expected "col2"
-- Test wrong number of columns (should fail)
COPY header_match_test FROM stdin WITH (format csv, header match);
ERROR:  wrong number of fields in header line: got 2, expected 3
-- Test HEADER MATCH with non-CSV format should fail
COPY header_match_test FROM stdin WITH (header match);
ERROR:  COPY HEADER MATCH requires CSV mode
-- Test HEADER MATCH in COPY TO should fail
COPY header_match_test (col1, col2) TO stdout WITH (format csv, header match);
ERROR:  cannot use "match" with HEADER in COPY TO
DROP TABLE header_match_test;
EOF

